        attribute gearRatio : Real;
        attribute efficiency : Real;

        constraint efficiencyConstraint {
            efficiency >= 0.85 and efficiency <= 1.0
        }
    }

    part def BrakeSubsystem :> Subsystem {
        attribute totalBrakeTorque : Real;
        attribute effectiveRadius : Real;
        attribute thermalCapacity : Real;
        attribute maxDeceleration : Real;

        constraint torqueConstraint {
            totalBrakeTorque > 0.0
        }

        constraint radiusConstraint {
            effectiveRadius > 0.0
        }

        constraint thermalCapacityConstraint {
            thermalCapacity > 0.0
        }

        constraint decelerationConstraint {
            maxDeceleration > 0.0
        }
    }

    part def Wheel {
        attribute diameter : Real;
        attribute width : Real;
        attribute tireRoadFriction : Real;

        constraint sizeConstraint {
            diameter >= 14.0 and diameter <= 22.0
        }

        constraint frictionConstraint {
            tireRoadFriction > 0.0 and tireRoadFriction <= 1.2
        }
    }

    part def Subsystem {
        attribute mass : Real;
        attribute cost : Real;
    }

    port def PowerPort {
        attribute voltage : Real;
        attribute current : Real;

        constraint powerLimit {
            voltage * current <= 1000.0
        }
    }

    requirement def PerformanceReq {
        doc /* The vehicle shall accelerate from 0 to 60 mph in less than 6 seconds */

        subject vehicle : Vehicle;

        require constraint {
            vehicle.engine.power >= 300.0
        }
    }

    requirement def SafetyReq {
        doc /* The vehicle shall stop from 27.0 m/s (approximately 60 mph) within 45.0 m under nominal dry-road conditions, with braking performance constrained by brake torque capacity, tire-road friction, and brake thermal capacity. */

        subject vehicle : Vehicle;

        require constraint {
            vehicle.brakes.totalBrakeTorque / vehicle.brakes.effectiveRadius >= vehicle.mass * vehicle.brakes.maxDeceleration and
            vehicle.brakes.maxDeceleration <= ((vehicle.wheels[1].tireRoadFriction + vehicle.wheels[2].tireRoadFriction + vehicle.wheels[3].tireRoadFriction + vehicle.wheels[4].tireRoadFriction) / vehicle.wheels.size) * 9.81 and
